mapper.update:
update bill
set is_deleted = 1
where id = #{id}
  and user_id = #{userId}
  and is_deleted = 0

mapper.select:
select b.id, b.amount, b.type, c.name as categoryName, b.remark, b.record_time as recordTime, b.is_ai_generated as isAiGenerated from bill b left join system_category c on b.category_id = c.id
b.user_id = #{userId} and b.is_deleted = 0
and b.record_time >= #{dto.startTime}
and b.record_time <= #{dto.endTime}
and b.type = #{dto.type}
and b.category_id = #{dto.categoryId}
order by b.record_time desc, b.id desc

select count(1)
from system_category
where id = #{categoryId}

select coalesce(sum(amount), 0)
from bill
where user_id = #{userId}
  and category_id = #{categoryId}
  and type = 2
  and is_deleted = 0
  and record_time  >=  #{startTime}
  and record_time  <  #{endTime}
